import React from 'react'
import logo from "../../assets/images/logo1.png";
import Gpic from "../../assets/images/gPic.png";
import { Link } from "react-router-dom";
import Axios from "../../Config/Axios";
import Redirect from "../../Utils/history";
import GoogleLogin from 'react-google-login';
import { toasterAlert as toastAlert, setSession, isAuthenticated } from "../../Helpers/Functions";
import userAuthenicated from '../../Services/auth.service'
import { addUser } from "../../app/Actions"
import { connect } from "react-redux";
import Polygon2 from "../../assets/images/angle-down.png";
import ApiRequest from '../../Services/ApiRequest'
import { RouteGuard } from '../../Services/RouteGuard';



class SpaceSelection extends React.Component {

    state = {
        isAnimationLoaded: false,
        spaces: [],
        mySpace:[],
        space_id:''
    }

    componentDidMount = async () => {
        RouteGuard('SpaceSelection')
        const response = await ApiRequest.getRequest('/getSpaces');
        console.log(response);
        if (response.status === 200 && response.data.spaces.length !== 0) {
            this.setState({
                spaces: response.data.spaces
            })
        }

        // Get User Added Space
        const getMySpace = await ApiRequest.getRequest('/mySpace');
        if (getMySpace.status === 200 && getMySpace.data.mySpaces.length !== 0) {
            
            this.setState({
                mySpace: getMySpace.data.mySpaces[0],
                space_id: getMySpace.data.mySpaces[0].career_space_id,
            })
        }
        

    }

    spacesHtml = () => {
        console.log(this.state.mySpace.career_space_id);
        return (
            <select name="degree_title" name="space_id" onChange={this.onChange} value={this.state.mySpace.career_space_id}>
                <option disable>Select options</option>
                {
                    this.state.spaces.map(el => {
                        return(
                            <option value={el.id}>{el.title}</option>
                        );
                    })
                }
                <img src={Polygon2} className="Polygon-icon" alt="" />
            </select>
            
        )
    }
    onChange = (event) => {
        const{name,value} = event.target;
        this.setState({
            [name]: value
        })
    }
    async spacesSubmit(){
        const{space_id} = this.state;
        const response = await ApiRequest.postRequest('/mySpace', {space_id:space_id})
        if(response && response.status == 200){
            Redirect.push('/MenteeProfile');
        }else{
            toastAlert('error','Something went wrong please try again');
        }

    }

    render() {
        return (
            <>
                <div className="container-fluid login-wrapper pending-status">
                    <div className="row mar-width-0 width-wrap">
                        <div className="col-md-12 text-center pt-2 ">
                            <Link to="/"> <img src={logo} alt="" /></Link>
                        </div>
                        <div className="col-md-12 login-heading">
                            <p className="font-family">Make the most of your professional life</p>
                        </div>

                        <div className="row mar-width-0 form-bg">
                            <div className="col-md-12 p-0">
                                <h3 className="font-family lo-title">Space Selection</h3>
                            </div>
                            <div className="col-md-12 form-wrap p-0">
                                <form className="w-100">
                                    <div className="form-group">
                                        <label htmlFor="exampleInputEmail1">Candoor Spaces <span>*</span></label>
                                        <div className="select-style-2 w-100" >
                                            {this.spacesHtml()}
                                        </div>
                                    </div>
                                    <button type="button" className="btn btn-primary" onClick={()=> this.spacesSubmit()}>Submit</button>
                                </form>
                            </div>
                        </div>


                    </div>
                </div>
            </>
        )
    }
}

export default SpaceSelection
